"""Status runtime for checking agent runtime status."""

import logging
from pathlib import Path
from typing import Optional

from rich.console import Console
from rich.table import Table

from agentcube.runtime.pack_runtime import PackRuntime

logger = logging.getLogger(__name__)
console = Console()


class StatusRuntime:
    """Status runtime for checking agent runtime status.

    Retrieves and displays status information from
    Kubernetes or AgentCube platform.
    """

    def __init__(self, workspace: str):
        """Initialize status runtime.

        Args:
            workspace: Path to workspace directory
        """
        self.workspace = Path(workspace)
        self.pack_runtime = PackRuntime(workspace)

    def status(
        self,
        name: str,
        provider: str = "kubernetes",
        namespace: str = "default",
        output_format: str = "table",
    ) -> tuple[bool, dict]:
        """Get runtime status.

        Args:
            name: Runtime name
            provider: Provider type
            namespace: Kubernetes namespace
            output_format: Output format (table/json)

        Returns:
            Tuple of (success, status dict)
        """
        logger.info(f"Getting status for {name} from {provider}")

        if provider == "kubernetes":
            return self._k8s_status(name, namespace)
        elif provider == "agenticube":
            return self._agenticube_status(name, namespace)
        else:
            return False, {"error": f"Unknown provider: {provider}"}

    def _k8s_status(self, name: str, namespace: str) -> tuple[bool, dict]:
        """Get status from Kubernetes.

        Args:
            name: Runtime name
            namespace: Kubernetes namespace

        Returns:
            Tuple of (success, status dict)
        """
        try:
            from kubernetes import client, config

            try:
                config.load_incluster_config()
            except Exception:
                config.load_kube_config()

            apps_v1 = client.AppsV1Api()

            try:
                deployment = apps_v1.read_namespaced_deployment(
                    name=name,
                    namespace=namespace,
                )

                replicas = deployment.spec.replicas or 0
                ready_replicas = deployment.status.ready_replicas or 0
                available_replicas = deployment.status.available_replicas or 0

                status_info = {
                    "name": name,
                    "namespace": namespace,
                    "replicas": replicas,
                    "ready_replicas": ready_replicas,
                    "available_replicas": available_replicas,
                    "phase": "Running" if ready_replicas > 0 else "Pending",
                    "conditions": [
                        {
                            "type": c.type,
                            "status": c.status,
                            "reason": c.reason,
                        }
                        for c in deployment.status.conditions or []
                    ],
                }

                return True, status_info

            except client.exceptions.ApiException as e:
                return False, {"error": f"K8s API error: {e}"}

        except ImportError:
            return False, {"error": "kubernetes package not installed"}
        except Exception as e:
            return False, {"error": str(e)}

    def _agenticube_status(self, name: str, namespace: str) -> tuple[bool, dict]:
        """Get status from AgentCube CR.

        Args:
            name: Runtime name
            namespace: Kubernetes namespace

        Returns:
            Tuple of (success, status dict)
        """
        try:
            from kubernetes import client, config
            from kubernetes.client.rest import ApiException

            try:
                config.load_incluster_config()
            except Exception:
                config.load_kube_config()

            custom_api = client.CustomObjectsApi()

            try:
                cr = custom_api.get_namespaced_custom_object(
                    group="runtime.agentcube.volcano.sh",
                    version="v1alpha1",
                    namespace=namespace,
                    plural="agentruntimes",
                    name=name,
                )

                status = cr.get("status", {})

                return True, {
                    "name": name,
                    "namespace": namespace,
                    "phase": status.get("phase", "Unknown"),
                    "conditions": status.get("conditions", []),
                    "endpoint": status.get("endpoint"),
                    "image": cr.get("spec", {}).get("image"),
                }

            except ApiException as e:
                return False, {"error": f"CR API error: {e}"}

        except ImportError:
            return False, {"error": "kubernetes package not installed"}
        except Exception as e:
            return False, {"error": str(e)}

    def display_status(self, status_info: dict) -> None:
        """Display status in table format.

        Args:
            status_info: Status information dict
        """
        if "error" in status_info:
            console.print(f"[red]Error: {status_info['error']}[/red]")
            return

        table = Table(title=f"Runtime Status: {status_info.get('name', 'Unknown')}")
        table.add_column("Property", style="cyan")
        table.add_column("Value", style="green")

        for key, value in status_info.items():
            if isinstance(value, list):
                value = f"{len(value)} items"
            elif isinstance(value, dict):
                value = str(value)
            table.add_row(key, str(value))

        console.print(table)

"""Kubernetes provider for standard K8s deployments."""

import logging
from typing import Optional

logger = logging.getLogger(__name__)


class KubernetesProvider:
    """Provider for deploying to standard Kubernetes.

    Creates Deployments and Services for agent runtimes.
    """

    def __init__(self, namespace: str = "default"):
        """Initialize Kubernetes provider.

        Args:
            namespace: Target namespace
        """
        self.namespace = namespace
        self._client = None

    def _get_client(self):
        """Get Kubernetes client."""
        if self._client is None:
            try:
                from kubernetes import client, config

                try:
                    config.load_incluster_config()
                except Exception:
                    config.load_kube_config()

                self._client = client
            except ImportError:
                raise ImportError("kubernetes package not installed")
        return self._client

    def deploy(
        self,
        name: str,
        image: str,
        replicas: int = 1,
        resources: Optional[dict] = None,
        port: int = 8080,
    ) -> tuple[bool, str]:
        """Deploy agent runtime to Kubernetes.

        Args:
            name: Deployment name
            image: Container image
            replicas: Number of replicas
            resources: Resource limits/requests
            port: Container port

        Returns:
            Tuple of (success, message)
        """
        try:
            client = self._get_client()
            apps_v1 = client.AppsV1Api()

            deployment_body = {
                "apiVersion": "apps/v1",
                "kind": "Deployment",
                "metadata": {
                    "name": name,
                    "namespace": self.namespace,
                    "labels": {"app": name},
                },
                "spec": {
                    "replicas": replicas,
                    "selector": {"matchLabels": {"app": name}},
                    "template": {
                        "metadata": {"labels": {"app": name}},
                        "spec": {
                            "containers": [{
                                "name": name,
                                "image": image,
                                "ports": [{"containerPort": port}],
                                "resources": resources or {},
                            }]
                        },
                    },
                },
            }

            apps_v1.create_namespaced_deployment(
                namespace=self.namespace,
                body=deployment_body,
            )

            service_body = {
                "apiVersion": "v1",
                "kind": "Service",
                "metadata": {
                    "name": name,
                    "namespace": self.namespace,
                },
                "spec": {
                    "selector": {"app": name},
                    "ports": [{"port": 80, "targetPort": port}],
                    "type": "ClusterIP",
                },
            }

            core_v1 = client.CoreV1Api()
            core_v1.create_namespaced_service(
                namespace=self.namespace,
                body=service_body,
            )

            logger.info(f"Deployed {name} to {self.namespace}")
            return True, f"Deployed {name} to namespace {self.namespace}"

        except Exception as e:
            error_msg = f"Deployment failed: {e}"
            logger.error(error_msg)
            return False, error_msg

    def delete(self, name: str) -> tuple[bool, str]:
        """Delete deployment.

        Args:
            name: Deployment name

        Returns:
            Tuple of (success, message)
        """
        try:
            client = self._get_client()
            apps_v1 = client.AppsV1Api()
            core_v1 = client.CoreV1Api()

            apps_v1.delete_namespaced_deployment(
                name=name,
                namespace=self.namespace,
            )

            try:
                core_v1.delete_namespaced_service(
                    name=name,
                    namespace=self.namespace,
                )
            except Exception:
                pass

            logger.info(f"Deleted {name}")
            return True, f"Deleted {name}"

        except Exception as e:
            error_msg = f"Delete failed: {e}"
            logger.error(error_msg)
            return False, error_msg

    def get_status(self, name: str) -> tuple[bool, dict]:
        """Get deployment status.

        Args:
            name: Deployment name

        Returns:
            Tuple of (success, status dict)
        """
        try:
            client = self._get_client()
            apps_v1 = client.AppsV1Api()

            deployment = apps_v1.read_namespaced_deployment(
                name=name,
                namespace=self.namespace,
            )

            return True, {
                "name": name,
                "replicas": deployment.spec.replicas,
                "ready_replicas": deployment.status.ready_replicas,
                "available_replicas": deployment.status.available_replicas,
            }

        except Exception as e:
            return False, {"error": str(e)}

"""Utility functions for AgentCube SDK."""

import os
from pathlib import Path
from typing import Optional


def read_token_from_file(token_path: str) -> Optional[str]:
    """Read auth token from file.

    Args:
        token_path: Path to token file

    Returns:
        Token string or None if not found
    """
    path = Path(token_path)
    if not path.exists():
        return None

    with open(path, 'r') as f:
        return f.read().strip()


def get_home_dir() -> Path:
    """Get user home directory."""
    return Path.home()


def get_config_dir() -> Path:
    """Get AgentCube config directory."""
    config_dir = os.environ.get("AGENTCUBE_CONFIG_DIR")
    if config_dir:
        return Path(config_dir)
    return get_home_dir() / ".agentcube"


def ensure_config_dir() -> Path:
    """Ensure config directory exists."""
    config_dir = get_config_dir()
    config_dir.mkdir(parents=True, exist_ok=True)
    return config_dir

"""Exception classes for AgentCube SDK."""


class AgentCubeError(Exception):
    """Base exception for AgentCube SDK."""

    def __init__(self, message: str, code: str = "UNKNOWN"):
        self.message = message
        self.code = code
        super().__init__(self.message)


class CommandExecutionError(AgentCubeError):
    """Error during command execution."""

    def __init__(self, message: str, exit_code: int = -1, output: str = ""):
        self.exit_code = exit_code
        self.output = output
        super().__init__(message, code="COMMAND_EXECUTION_ERROR")


class SessionError(AgentCubeError):
    """Error related to session management."""

    def __init__(self, message: str, session_id: str = ""):
        self.session_id = session_id
        super().__init__(message, code="SESSION_ERROR")


class ConnectionError(AgentCubeError):
    """Error during connection to AgentCube services."""

    def __init__(self, message: str, url: str = ""):
        self.url = url
        super().__init__(message, code="CONNECTION_ERROR")


class AuthenticationError(AgentCubeError):
    """Error during authentication."""

    def __init__(self, message: str):
        super().__init__(message, code="AUTHENTICATION_ERROR")


class TimeoutError(AgentCubeError):
    """Error due to request timeout."""

    def __init__(self, message: str, timeout: float = 0):
        self.timeout = timeout
        super().__init__(message, code="TIMEOUT_ERROR")


class ValidationError(AgentCubeError):
    """Error during input validation."""

    def __init__(self, message: str, field: str = ""):
        self.field = field
        super().__init__(message, code="VALIDATION_ERROR")

"""Control plane client for Workload Manager."""

import json
from typing import Any, Dict, Optional, Tuple

import requests

from agentcube.exceptions import AuthenticationError, ConnectionError, TimeoutError
from agentcube.utils.http import create_session
from agentcube.utils.log import get_logger

logger = get_logger(__name__)


class ControlPlaneClient:
    """Client for Workload Manager control plane.

    Handles agent runtime lifecycle operations like
    create, delete, and status retrieval.
    """

    def __init__(
        self,
        endpoint: str,
        token: Optional[str] = None,
        timeout: Tuple[float, float] = (5.0, 30.0),
    ):
        """Initialize control plane client.

        Args:
            endpoint: Workload Manager endpoint URL
            token: Optional auth token
            timeout: Connect and read timeout tuple
        """
        self.endpoint = endpoint.rstrip('/')
        self.token = token
        self.timeout = timeout
        self._session = create_session(timeout=timeout)

        if token:
            self._session.headers.update({"Authorization": f"Bearer {token}"})

    def create_runtime(
        self,
        name: str,
        image: str,
        version: str = "0.1.0",
        replicas: int = 1,
        resources: Optional[Dict] = None,
    ) -> Tuple[bool, Dict]:
        """Create agent runtime.

        Args:
            name: Runtime name
            image: Container image
            version: Runtime version
            replicas: Number of replicas
            resources: Resource limits/requests

        Returns:
            Tuple of (success, response data)
        """
        url = f"{self.endpoint}/api/v1/runtimes"
        payload = {
            "name": name,
            "image": image,
            "version": version,
            "replicas": replicas,
            "resources": resources or {},
        }

        try:
            response = self._session.post(url, json=payload)
            response.raise_for_status()
            return True, response.json()
        except requests.exceptions.HTTPError as e:
            if e.response.status_code == 401:
                raise AuthenticationError("Invalid or missing token")
            return False, {"error": str(e)}
        except requests.exceptions.Timeout:
            raise TimeoutError("Request timed out", timeout=self.timeout[1])
        except requests.exceptions.RequestException as e:
            raise ConnectionError(f"Connection failed: {e}", url=url)

    def delete_runtime(self, name: str) -> Tuple[bool, Dict]:
        """Delete agent runtime.

        Args:
            name: Runtime name

        Returns:
            Tuple of (success, response data)
        """
        url = f"{self.endpoint}/api/v1/runtimes/{name}"

        try:
            response = self._session.delete(url)
            response.raise_for_status()
            return True, {"message": "Runtime deleted"}
        except requests.exceptions.HTTPError as e:
            if e.response.status_code == 401:
                raise AuthenticationError("Invalid or missing token")
            return False, {"error": str(e)}
        except requests.exceptions.Timeout:
            raise TimeoutError("Request timed out", timeout=self.timeout[1])
        except requests.exceptions.RequestException as e:
            raise ConnectionError(f"Connection failed: {e}", url=url)

    def get_runtime(self, name: str) -> Tuple[bool, Dict]:
        """Get runtime details.

        Args:
            name: Runtime name

        Returns:
            Tuple of (success, runtime data)
        """
        url = f"{self.endpoint}/api/v1/runtimes/{name}"

        try:
            response = self._session.get(url)
            response.raise_for_status()
            return True, response.json()
        except requests.exceptions.HTTPError as e:
            if e.response.status_code == 404:
                return False, {"error": f"Runtime not found: {name}"}
            if e.response.status_code == 401:
                raise AuthenticationError("Invalid or missing token")
            return False, {"error": str(e)}
        except requests.exceptions.Timeout:
            raise TimeoutError("Request timed out", timeout=self.timeout[1])
        except requests.exceptions.RequestException as e:
            raise ConnectionError(f"Connection failed: {e}", url=url)

    def list_runtimes(self) -> Tuple[bool, Dict]:
        """List all runtimes.

        Returns:
            Tuple of (success, list of runtimes)
        """
        url = f"{self.endpoint}/api/v1/runtimes"

        try:
            response = self._session.get(url)
            response.raise_for_status()
            return True, response.json()
        except requests.exceptions.HTTPError as e:
            if e.response.status_code == 401:
                raise AuthenticationError("Invalid or missing token")
            return False, {"error": str(e)}
        except requests.exceptions.Timeout:
            raise TimeoutError("Request timed out", timeout=self.timeout[1])
        except requests.exceptions.RequestException as e:
            raise ConnectionError(f"Connection failed: {e}", url=url)

    def health(self) -> Tuple[bool, Dict]:
        """Check control plane health.

        Returns:
            Tuple of (healthy, status)
        """
        url = f"{self.endpoint}/health"

        try:
            response = self._session.get(url, timeout=5.0)
            response.raise_for_status()
            return True, response.json()
        except Exception as e:
            return False, {"error": str(e)}

    def close(self) -> None:
        """Close HTTP session."""
        self._session.close()

    def __enter__(self):
        """Context manager entry."""
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        """Context manager exit."""
        self.close()

"""Code interpreter data plane client for Router."""

import json
from typing import Any, Dict, List, Optional, Tuple

import requests

from agentcube.exceptions import (
    AuthenticationError,
    CommandExecutionError,
    ConnectionError,
    SessionError,
    TimeoutError,
)
from agentcube.utils.http import create_session
from agentcube.utils.log import get_logger

logger = get_logger(__name__)


class CodeInterpreterDataPlaneClient:
    """Client for Code Interpreter data plane.

    Handles session-based code execution through Router.
    """

    def __init__(
        self,
        endpoint: str,
        token: Optional[str] = None,
        timeout: Tuple[float, float] = (5.0, 60.0),
    ):
        """Initialize data plane client.

        Args:
            endpoint: Router endpoint URL
            token: Optional auth token
            timeout: Connect and read timeout tuple
        """
        self.endpoint = endpoint.rstrip('/')
        self.token = token
        self.timeout = timeout
        self._session = create_session(timeout=timeout)

        if token:
            self._session.headers.update({"Authorization": f"Bearer {token}"})

    def execute(
        self,
        command: str,
        session_id: Optional[str] = None,
        timeout: Optional[float] = None,
    ) -> Tuple[bool, Dict]:
        """Execute code command.

        Args:
            command: Code to execute
            session_id: Optional session ID
            timeout: Optional command timeout

        Returns:
            Tuple of (success, execution result)
        """
        url = f"{self.endpoint}/api/v1/execute"
        payload = {"command": command}

        headers = dict(self._session.headers)
        if session_id:
            headers["X-Session-ID"] = session_id
        if timeout:
            headers["X-Command-Timeout"] = str(timeout)

        try:
            response = self._session.post(url, json=payload, headers=headers)
            response.raise_for_status()
            result = response.json()

            if result.get("exit_code", 0) != 0:
                raise CommandExecutionError(
                    result.get("error", "Command failed"),
                    exit_code=result.get("exit_code", -1),
                    output=result.get("output", ""),
                )

            return True, result

        except requests.exceptions.HTTPError as e:
            if e.response.status_code == 401:
                raise AuthenticationError("Invalid or missing token")
            return False, {"error": str(e)}
        except requests.exceptions.Timeout:
            raise TimeoutError("Request timed out", timeout=timeout or self.timeout[1])
        except requests.exceptions.RequestException as e:
            raise ConnectionError(f"Connection failed: {e}", url=url)

    def create_session(self, ttl: int = 3600) -> Tuple[bool, Dict]:
        """Create new session.

        Args:
            ttl: Session TTL in seconds

        Returns:
            Tuple of (success, session info)
        """
        url = f"{self.endpoint}/api/v1/sessions"
        payload = {"ttl": ttl}

        try:
            response = self._session.post(url, json=payload)
            response.raise_for_status()
            return True, response.json()
        except requests.exceptions.HTTPError as e:
            if e.response.status_code == 401:
                raise AuthenticationError("Invalid or missing token")
            return False, {"error": str(e)}
        except requests.exceptions.Timeout:
            raise TimeoutError("Request timed out", timeout=self.timeout[1])
        except requests.exceptions.RequestException as e:
            raise ConnectionError(f"Connection failed: {e}", url=url)

    def get_session(self, session_id: str) -> Tuple[bool, Dict]:
        """Get session info.

        Args:
            session_id: Session ID

        Returns:
            Tuple of (success, session info)
        """
        url = f"{self.endpoint}/api/v1/sessions/{session_id}"

        try:
            response = self._session.get(url)
            response.raise_for_status()
            return True, response.json()
        except requests.exceptions.HTTPError as e:
            if e.response.status_code == 404:
                raise SessionError(f"Session not found: {session_id}", session_id=session_id)
            if e.response.status_code == 401:
                raise AuthenticationError("Invalid or missing token")
            return False, {"error": str(e)}
        except requests.exceptions.Timeout:
            raise TimeoutError("Request timed out", timeout=self.timeout[1])
        except requests.exceptions.RequestException as e:
            raise ConnectionError(f"Connection failed: {e}", url=url)

    def delete_session(self, session_id: str) -> Tuple[bool, Dict]:
        """Delete session.

        Args:
            session_id: Session ID

        Returns:
