"""Dify plugin integration for AgentCube."""

from dify_plugin import AgentProvider, ToolProvider


class AgentcubeCodeInterpreterProvider(ToolProvider):
    """AgentCube Code Interpreter provider for Dify."""

    def validate_credentials(self, credentials: dict) -> bool:
        """Validate provider credentials.

        Args:
            credentials: Provider credentials dict

        Returns:
            True if valid
        """
        required = ["control_endpoint", "data_endpoint", "token"]
        for field in required:
            if field not in credentials:
                raise ValueError(f"Missing required credential: {field}")
        return True


class AgentcubeCodeInterpreterTool:
    """AgentCube Code Interpreter tool for Dify."""

    def __init__(self, credentials: dict):
        """Initialize tool.

        Args:
            credentials: Provider credentials
        """
        self.credentials = credentials
        self._client = None

    def _get_client(self):
        """Get AgentCube client."""
        if self._client is None:
            from agentcube.code_interpreter import CodeInterpreterClient
            self._client = CodeInterpreterClient(
                control_endpoint=self.credentials["control_endpoint"],
                data_endpoint=self.credentials["data_endpoint"],
                token=self.credentials.get("token"),
            )
        return self._client

    def invoke(self, parameters: dict) -> dict:
        """Execute code command.

        Args:
            parameters: Tool parameters

        Returns:
            Execution result
        """
        client = self._get_client()

        command = parameters.get("command", "")
        if not command:
            return {"error": "No command provided"}

        success, result = client.execute(command)

        if success:
            return {
                "output": result.get("output", ""),
                "exit_code": result.get("exit_code", 0),
            }
        else:
            return {"error": result.get("error", "Execution failed")}

